s = input().strip()
n = len(s)

count = 0

for x_val in range(10):
    for blank_vals in range(10**s.count('_')):
        # Fill in the string
        filled = []
        blank_idx = 0
        blanks = []
        # Extract blank digits from blank_vals
        num_blanks = s.count('_')
        blank_digits = []
        temp = blank_vals
        for i in range(num_blanks):
            blank_digits.append(temp % 10)
            temp //= 10

        filled = []
        b_idx = 0
        for c in s:
            if c == 'X':
                filled.append(str(x_val))
            elif c == '_':
                filled.append(str(blank_digits[b_idx]))
                b_idx += 1
            else:
                filled.append(c)

        num_str = ''.join(filled)

        # Check leading zeros
        # Special case: if the number is "0", it's valid
        if len(num_str) == 1:
            if num_str == '0':
                # valid, no leading zero
                pass
            else:
                if num_str[0] == '0':
                    continue
        else:
            if num_str[0] == '0':
                continue

        # Check divisible by 25
        num = int(num_str)
        if num % 25 == 0:
            count += 1

print(count)

